// sqs-financial-consumer.js

const { SQSClient, ReceiveMessageCommand, DeleteMessageCommand } = require("@aws-sdk/client-sqs");
const { DynamoDBClient } = require("@aws-sdk/client-dynamodb");
const { DynamoDBDocumentClient, PutCommand, GetCommand, UpdateCommand } = require("@aws-sdk/lib-dynamodb");
const { KMSClient, DecryptCommand } = require("@aws-sdk/client-kms");
const crypto = require("crypto");

// Configuration with validation
const CONFIG = {
  QUEUE_URL: process.env.SQS_QUEUE_URL,
  REGION: process.env.AWS_REGION || "us-east-1",
  TRANSACTIONS_TABLE: process.env.TRANSACTIONS_TABLE || "financial_transactions",
  IDEMPOTENCY_TABLE: process.env.IDEMPOTENCY_TABLE || "transaction_idempotency",
  MAX_MESSAGES: 10,
  WAIT_TIME_SECONDS: 20, // Long polling to reduce empty receives
  VISIBILITY_TIMEOUT: 60,
  MAX_RETRIES: 3,
  POLL_INTERVAL_MS: 1000,
  IDEMPOTENCY_TTL_HOURS: 24,
  KMS_KEY_ID: process.env.KMS_KEY_ID,
};

// Validate required configuration at startup
function validateConfig() {
  const required = ["QUEUE_URL", "TRANSACTIONS_TABLE", "IDEMPOTENCY_TABLE"];
  const missing = required.filter((key) => !CONFIG[key]);
  if (missing.length > 0) {
    throw new Error(`Missing required configuration: ${missing.join(", ")}`);
  }
}

// Initialize AWS clients
const sqsClient = new SQSClient({ region: CONFIG.REGION });
const dynamoClient = new DynamoDBClient({ region: CONFIG.REGION });
const docClient = DynamoDBDocumentClient.from(dynamoClient);
const kmsClient = new KMSClient({ region: CONFIG.REGION });

// Structured logging for audit trail
class AuditLogger {
  static log(level, event, data = {}) {
    const entry = {
      timestamp: new Date().toISOString(),
      level,
      event,
      service: "payment-sqs-consumer",
      ...data,
    };
    // Redact sensitive fields
    if (entry.accountNumber) {
      entry.accountNumber = AuditLogger.redact(entry.accountNumber);
    }
    if (entry.cardNumber) {
      entry.cardNumber = AuditLogger.redact(entry.cardNumber);
    }
    console.log(JSON.stringify(entry));
  }

  static redact(value) {
    if (!value || typeof value !== "string") return "***";
    if (value.length <= 4) return "***";
    return "***" + value.slice(-4);
  }

  static info(event, data) { AuditLogger.log("INFO", event, data); }
  static warn(event, data) { AuditLogger.log("WARN", event, data); }
  static error(event, data) { AuditLogger.log("ERROR", event, data); }
}

// Input validation and sanitization for financial messages
class TransactionValidator {
  static VALID_TRANSACTION_TYPES = ["credit", "debit", "transfer", "refund"];
  static MAX_AMOUNT = 1_000_000; // Configurable limit
  static MIN_AMOUNT = 0.01;

  static validate(transaction) {
    const errors = [];

    // Transaction ID - required, must be UUID format
    if (!transaction.transactionId) {
      errors.push("transactionId is required");
    } else if (!TransactionValidator.isValidUUID(transaction.transactionId)) {
      errors.push("transactionId must be a valid UUID");
    }

    // Transaction type
    if (!transaction.type) {
      errors.push("type is required");
    } else if (!TransactionValidator.VALID_TRANSACTION_TYPES.includes(transaction.type)) {
      errors.push(`type must be one of: ${TransactionValidator.VALID_TRANSACTION_TYPES.join(", ")}`);
    }

    // Amount validation
    if (transaction.amount === undefined || transaction.amount === null) {
      errors.push("amount is required");
    } else {
      const amount = Number(transaction.amount);
      if (isNaN(amount)) {
        errors.push("amount must be a valid number");
      } else if (amount < TransactionValidator.MIN_AMOUNT) {
        errors.push(`amount must be at least ${TransactionValidator.MIN_AMOUNT}`);
      } else if (amount > TransactionValidator.MAX_AMOUNT) {
        errors.push(`amount must not exceed ${TransactionValidator.MAX_AMOUNT}`);
      }
      // Check for floating point precision issues - max 2 decimal places
      if (!isNaN(amount) && !Number.isInteger(amount * 100)) {
        errors.push("amount must have at most 2 decimal places");
      }
    }

    // Currency
    if (!transaction.currency) {
      errors.push("currency is required");
    } else if (!/^[A-Z]{3}$/.test(transaction.currency)) {
      errors.push("currency must be a valid 3-letter ISO code");
    }

    // Account IDs
    if (!transaction.sourceAccountId) {
      errors.push("sourceAccountId is required");
    } else if (!TransactionValidator.isValidAccountId(transaction.sourceAccountId)) {
      errors.push("sourceAccountId format is invalid");
    }

    if (transaction.type === "transfer") {
      if (!transaction.destinationAccountId) {
        errors.push("destinationAccountId is required for transfers");
      } else if (!TransactionValidator.isValidAccountId(transaction.destinationAccountId)) {
        errors.push("destinationAccountId format is invalid");
      }
    }

    // Timestamp validation
    if (!transaction.timestamp) {
      errors.push("timestamp is required");
    } else {
      const ts = new Date(transaction.timestamp);
      if (isNaN(ts.getTime())) {
        errors.push("timestamp must be a valid ISO 8601 date");
      } else {
        // Reject transactions too far in the past or future
        const now = Date.now();
        const oneHourMs = 3600000;
        if (ts.getTime() > now + oneHourMs) {
          errors.push("timestamp cannot be more than 1 hour in the future");
        }
        if (ts.getTime() < now - 24 * oneHourMs) {
          errors.push("timestamp cannot be more than 24 hours in the past");
        }
      }
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  static isValidUUID(str) {
    return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(str);
  }

  static isValidAccountId(str) {
    // Alphanumeric, dashes, 8-36 characters
    return /^[a-zA-Z0-9-]{8,36}$/.test(str);
  }

  static sanitize(transaction) {
    return {
      transactionId: String(transaction.transactionId).trim(),
      type: String(transaction.type).trim().toLowerCase(),
      amount: Math.round(Number(transaction.amount) * 100) / 100, // Ensure 2 decimal places
      currency: String(transaction.currency).trim().toUpperCase(),
      sourceAccountId: String(transaction.sourceAccountId).trim(),
      destinationAccountId: transaction.destinationAccountId
        ? String(transaction.destinationAccountId).trim()
        : null,
      timestamp: new Date(transaction.timestamp).toISOString(),
      description: transaction.description
        ? String(transaction.description).trim().substring(0, 500)
        : null,
    };
  }
}

// Message integrity verification
class MessageIntegrity {
  static verifyMessageHash(message) {
    if (!message.MessageAttributes?.IntegrityHash?.StringValue) {
      AuditLogger.warn("MESSAGE_MISSING_INTEGRITY_HASH", {
        messageId: message.MessageId,
      });
      // In strict mode, you might reject messages without integrity hashes
      return true; // Allowing for backward compatibility, but logging
    }

    const expectedHash = message.MessageAttributes.IntegrityHash.StringValue;
    const computedHash = crypto
      .createHmac("sha256", process.env.MESSAGE_HMAC_SECRET || "")
      .update(message.Body)
      .digest("hex");

    if (computedHash !== expectedHash) {
      AuditLogger.error("MESSAGE_INTEGRITY_FAILURE", {
        messageId: message.MessageId,
        expected: expectedHash,
        computed: computedHash,
      });
      return false;
    }

    return true;
  }
}

// CRITICAL: Idempotency check to prevent duplicate transaction processing
// SQS has at-least-once delivery - duplicates WILL happen in production
class IdempotencyStore {
  static async checkAndLock(transactionId) {
    const now = Date.now();
    const ttl = Math.floor(now / 1000) + CONFIG.IDEMPOTENCY_TTL_HOURS * 3600;

    try {
      // Conditional put - only succeeds if the item doesn't already exist
      await docClient.send(
        new PutCommand({
          TableName: CONFIG.IDEMPOTENCY_TABLE,
          Item: {
            transactionId,
            status: "PROCESSING",
            lockedAt: now,
            ttl,
          },
          ConditionExpression: "attribute_not_exists(transactionId) OR #s = :failed",
          ExpressionAttributeNames: { "#s": "status" },
          ExpressionAttributeValues: { ":failed": "FAILED" },
        })
      );
      return { isNew: true };
    } catch (error) {
      if (error.name === "ConditionalCheckFailedException") {
        // Transaction already processed or in progress
        const existing = await docClient.send(
          new GetCommand({
            TableName: CONFIG.IDEMPOTENCY_TABLE,
            Key: { transactionId },
          })
        );
        return {
          isNew: false,
          existingStatus: existing.Item?.status,
        };
      }
      throw error;
    }
  }

  static async markCompleted(transactionId, result) {
    await docClient.send(
      new UpdateCommand({
        TableName: CONFIG.IDEMPOTENCY_TABLE,
        Key: { transactionId },
        UpdateExpression: "SET #s = :status, completedAt = :now, #r = :result",
        ExpressionAttributeNames: { "#s": "status", "#r": "result" },
        ExpressionAttributeValues: {
          ":status": "COMPLETED",
          ":now": Date.now(),
          ":result": result || "SUCCESS",
        },
      })
    );
  }

  static async markFailed(transactionId, error) {
    await docClient.send(
      new UpdateCommand({
        TableName: CONFIG.IDEMPOTENCY_TABLE,
        Key: { transactionId },
        UpdateExpression: "SET #s = :status, failedAt = :now, errorMessage = :err",
        ExpressionAttributeNames: { "#s": "status" },
        ExpressionAttributeValues: {
          ":status": "FAILED",
          ":now": Date.now(),
          ":err": String(error).substring(0, 1000),
        },
      })
    );
  }
}

// Transaction processor with proper error handling
class TransactionProcessor {
  static async process(transaction) {
    AuditLogger.info("TRANSACTION_PROCESSING_START", {
      transactionId: transaction.transactionId,
      type: transaction.type,
      amount: transaction.amount,
      currency: transaction.currency,
    });

    const now = Date.now();
    const ttl = Math.floor(now / 1000) + 90 * 24 * 3600; // 90 day retention

    // Store the transaction record
    await docClient.send(
      new PutCommand({
        TableName: CONFIG.TRANSACTIONS_TABLE,
        Item: {
          transactionId: transaction.transactionId,
          type: transaction.type,
          amount: transaction.amount,
          currency: transaction.currency,
          sourceAccountId: transaction.sourceAccountId,
          destinationAccountId: transaction.destinationAccountId,
          description: transaction.description,
          originalTimestamp: transaction.timestamp,
          processedAt: new Date().toISOString(),
          status: "COMPLETED",
          ttl,
        },
        // Prevent overwriting an existing completed transaction
        ConditionExpression: "attribute_not_exists(transactionId) OR #s <> :completed",
        ExpressionAttributeNames: { "#s": "status" },
        ExpressionAttributeValues: { ":completed": "COMPLETED" },
      })
    );

    AuditLogger.info("TRANSACTION_PROCESSING_COMPLETE", {
      transactionId: transaction.transactionId,
    });

    return { success: true, transactionId: transaction.transactionId };
  }
}

// Dead letter queue handler for messages that fail repeatedly
class FailedMessageHandler {
  static async handlePoisonMessage(message, error) {
    AuditLogger.error("POISON_MESSAGE_DETECTED", {
      messageId: message.MessageId,
      receiveCount: message.Attributes?.ApproximateReceiveCount,
      error: String(error),
    });
    // In production, you'd move this to a DLQ or alert operations
    // The SQS redrive policy handles DLQ routing automatically
  }
}

// Main consumer
class SQSFinancialConsumer {
  constructor() {
    this.isRunning = false;
    this.processedCount = 0;
    this.errorCount = 0;
    this.duplicateCount = 0;
  }

  async start() {
    validateConfig();
    this.isRunning = true;

    AuditLogger.info("CONSUMER_STARTED", {
      queueUrl: CONFIG.QUEUE_URL,
      region: CONFIG.REGION,
    });

    while (this.isRunning) {
      try {
        await this.pollMessages();
      } catch (error) {
        AuditLogger.error("POLL_CYCLE_ERROR", { error: error.message });
        // Back off on errors to avoid hammering a failing service
        await this.sleep(5000);
      }
    }

    AuditLogger.info("CONSUMER_STOPPED", {
      processedCount: this.processedCount,
      errorCount: this.errorCount,
      duplicateCount: this.duplicateCount,
    });
  }

  stop() {
    AuditLogger.info("CONSUMER_STOP_REQUESTED");
    this.isRunning = false;
  }

  async pollMessages() {
    const command = new ReceiveMessageCommand({
      QueueUrl: CONFIG.QUEUE_URL,
      MaxNumberOfMessages: CONFIG.MAX_MESSAGES,
      WaitTimeSeconds: CONFIG.WAIT_TIME_SECONDS,
      VisibilityTimeout: CONFIG.VISIBILITY_TIMEOUT,
      MessageAttributeNames: ["All"],
      AttributeNames: ["ApproximateReceiveCount", "SentTimestamp"],
    });

    const response = await sqsClient.send(command);

    if (!response.Messages || response.Messages.length === 0) {
      return;
    }

    AuditLogger.info("MESSAGES_RECEIVED", { count: response.Messages.length });

    // Process messages concurrently but with controlled parallelism
    const results = await Promise.allSettled(
      response.Messages.map((msg) => this.processMessage(msg))
    );

    for (const result of results) {
      if (result.status === "rejected") {
        AuditLogger.error("UNHANDLED_MESSAGE_ERROR", {
          error: result.reason?.message,
        });
      }
    }
  }

  async processMessage(message) {
    const messageId = message.MessageId;
    const receiveCount = parseInt(message.Attributes?.ApproximateReceiveCount || "1", 10);

    try {
      // Step 1: Verify message integrity
      if (!MessageIntegrity.verifyMessageHash(message)) {
        AuditLogger.error("MESSAGE_REJECTED_INTEGRITY", { messageId });
        // Delete tampered messages - they should not be retried
        await this.deleteMessage(message.ReceiptHandle);
        return;
      }

      // Step 2: Parse message body safely
      let transactionData;
      try {
        transactionData = JSON.parse(message.Body);
      } catch (parseError) {
        AuditLogger.error("MESSAGE_PARSE_FAILURE", {
          messageId,
          error: parseError.message,
        });
        // Malformed JSON will never succeed on retry - delete it
        await this.deleteMessage(message.ReceiptHandle);
        return;
      }

      // Step 3: Validate transaction data
      const validation = TransactionValidator.validate(transactionData);
      if (!validation.isValid) {
        AuditLogger.error("TRANSACTION_VALIDATION_FAILED", {
          messageId,
          errors: validation.errors,
          transactionId: transactionData.transactionId,
        });
        // Invalid data will never succeed on retry - delete it
        await this.deleteMessage(message.ReceiptHandle);
        return;
      }

      // Step 4: Sanitize input
      const sanitizedTransaction = TransactionValidator.sanitize(transactionData);

      // Step 5: CRITICAL - Idempotency check
      // SQS guarantees at-least-once delivery, NOT exactly-once.
      // Without this check, duplicate messages WILL cause duplicate charges.
      const idempotencyResult = await IdempotencyStore.checkAndLock(
        sanitizedTransaction.transactionId
      );

      if (!idempotencyResult.isNew) {
        this.duplicateCount++;
        AuditLogger.warn("DUPLICATE_TRANSACTION_DETECTED", {
          messageId,
          transactionId: sanitizedTransaction.transactionId,
          existingStatus: idempotencyResult.existingStatus,
        });
        // Delete the duplicate message from the queue
        await this.deleteMessage(message.ReceiptHandle);
        return;
      }

      // Step 6: Process the transaction
      try {
        const result = await TransactionProcessor.process(sanitizedTransaction);
        await IdempotencyStore.markCompleted(sanitizedTransaction.transactionId, "SUCCESS");
        this.processedCount++;

        AuditLogger.info("TRANSACTION_SUCCESS", {
          messageId,
          transactionId: sanitizedTransaction.transactionId,
        });
      } catch (processingError) {
        await IdempotencyStore.markFailed(
          sanitizedTransaction.transactionId,
          processingError.message
        );
        throw processingError; // Re-throw to trigger retry via visibility timeout
      }

      // Step 7: Delete message only after successful processing
      await this.deleteMessage(message.ReceiptHandle);
    } catch (error) {
      this.errorCount++;

      AuditLogger.error("MESSAGE_PROCESSING_ERROR", {
        messageId,
        receiveCount,
        error: error.message,
      });

      // If message has been retried too many times, log for investigation
      // SQS redrive policy will move it to DLQ after maxReceiveCount
      if (receiveCount >= CONFIG.MAX_RETRIES) {
        await FailedMessageHandler.handlePoisonMessage(message, error);
      }

      // Do NOT delete the message - let it become visible again for retry
      // or be moved to DLQ by the redrive policy
    }
  }

  async deleteMessage(receiptHandle) {
    try {
      await sqsClient.send(
        new DeleteMessageCommand({
          QueueUrl: CONFIG.QUEUE_URL,
          ReceiptHandle: receiptHandle,
        })
      );
    } catch (error) {
      AuditLogger.error("MESSAGE_DELETE_FAILED", {
        error: error.message,
      });
      // Non-fatal: message will become visible again and be reprocessed
      // Idempotency check will prevent duplicate processing
    }
  }

  sleep(ms) {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }

  getStats() {
    return {
      processedCount: this.processedCount,
      errorCount: this.errorCount,
      duplicateCount: this.duplicateCount,
      isRunning: this.isRunning,
    };
  }
}

// Graceful shutdown handling
const consumer = new SQSFinancialConsumer();

process.on("SIGTERM", () => {
  AuditLogger.info("SIGTERM_RECEIVED");
  consumer.stop();
});

process.on("SIGINT", () => {
  AuditLogger.info("SIGINT_RECEIVED");
  consumer.stop();
});

process.on("uncaughtException", (error) => {
  AuditLogger.error("UNCAUGHT_EXCEPTION", {
    error: error.message,
    stack: error.stack,
  });
  consumer.stop();
  process.exit(1);
});

process.on("unhandledRejection", (reason) => {
  AuditLogger.error("UNHANDLED_REJECTION", {
    reason: String(reason),
  });
});

// Start the consumer
consumer.start().catch((error) => {
  AuditLogger.error("CONSUMER_FATAL_ERROR", { error: error.message });
  process.exit(1);
});

